function fetchData(){fetch("/api/data").then(a=>a.json()).then(a=>{let t='<h2>Device Data</h2><div class="data-grid">';for(const[e,n]of Object.entries(a))t+=`<div class="data-item"><span class="data-label">${e}</span><span class="data-value">${n}</span></div>`;t+="</div>",document.getElementById("dataDisplay").innerHTML=t}).catch(a=>{console.error("Error fetching data:",a),document.getElementById("dataDisplay").innerHTML="<h2>Device Data</h2><p>Error loading data</p>"})}fetchData(),setInterval(fetchData,5e3);